Task 4: Trends in Success Over Time


Show code
genre_decade &lt;- movie_success |&gt;
  filter(!is.na(genres), genres != "\\N", startYear &gt;= 1960) |&gt;
  separate_longer_delim(genres, ",") |&gt;
  mutate(success = success_score &gt;= success_threshold) |&gt;
  group_by(decade, genres) |&gt;
  summarize(
    titles = n(),
    successes = sum(success, na.rm = TRUE),
    success_rate = successes / titles,
    .groups = "drop"
  ) |&gt;
  filter(titles &gt;= 20)

top_genre_each_decade &lt;- genre_decade |&gt;
  group_by(decade) |&gt;
  slice_max(successes, n = 1, with_ties = FALSE) |&gt;
  ungroup()

post_2010_genres &lt;- genre_decade |&gt;
  filter(decade &gt;= 2010) |&gt;
  group_by(genres) |&gt;
  summarize(
    titles = sum(titles),
    successes = sum(successes),
    success_rate = successes / titles,
    .groups = "drop"
  ) |&gt;
  arrange(desc(successes))

selected_genre &lt;- post_2010_genres |&gt;
  filter(titles &gt;= 100) |&gt;
  slice_max(success_rate, n = 1, with_ties = FALSE) |&gt;
  pull(genres)




Show code
top_genre_each_decade |&gt;
  ggplot(aes(x = decade, y = successes, fill = genres)) +
  geom_col(show.legend = FALSE) +
  geom_text(aes(label = genres), vjust = -0.2, size = 3) +
  labs(title = "Most Successful Genre by Decade", x = "Decade", y = "Number of successful movies") +
  theme_minimal()









Show code
post_2010_genres |&gt;
  slice_max(successes, n = 12) |&gt;
  ggplot(aes(x = reorder(genres, successes), y = successes, fill = success_rate)) +
  geom_col() +
  coord_flip() +
  scale_fill_viridis_c(labels = percent) +
  labs(
    title = "Post-2010 Genre Success",
    subtitle = "Counts and rates can tell different stories",
    x = NULL,
    y = "Successful movies",
    fill = "Success rate"
  ) +
  theme_minimal()









I select Biography as the target genre. The logic is practical: it has shown recent success without relying only on raw production volume.

